def validate_cart_items(cart):
    # Implement cart item validation logic here
    if not all(item['quantity'] > 0 for item in cart):
        raise ValueError("All items must have a quantity greater than zero.")
    return {"validated_cart": cart}

def apply_discount_codes(validated_cart, discount_codes, user_permissions):
    # Implement discount code application logic here
    available_codes = {
        "ADMIN_CODE": {"amount": 20, "permission": "admin"},
        "VIP_CODE": {"amount": 15, "permission": "vip"},
        "GENERAL_CODE": {"amount": 10, "permission": None}
    }
    
    total_discount = 0
    applied_codes = []
    
    for code in discount_codes:
        if code not in available_codes:
            continue
        
        discount_info = available_codes[code]
        
        if user_permissions.get(code, "none") != discount_info["permission"] and discount_info["permission"]:
            continue
        
        total_discount += discount_info["amount"]
        applied_codes.append(code)
    
    return {
        "discounted_cart": validated_cart,
        "total_discount": total_discount,
        "applied_codes": applied_codes
    }

def calculate_tax(discounted_cart, tax_rate):
    # Implement tax calculation logic here
    subtotal = sum(item['price'] * item['quantity'] for item in discounted_cart)
    tax_amount = subtotal * (tax_rate / 100)
    return {
        "cart_with_tax": discounted_cart,
        "tax_amount": tax_amount
    }

def process_payment(cart_with_tax, total_discount, tax_amount, payment_details):
    # Implement payment processing logic here
    if not payment_details.get("approved"):
        raise Exception("Payment was declined.")
    
    final_total = sum(item['price'] * item['quantity'] for item in cart_with_tax) - total_discount + tax_amount
    return {
        "payment_processed": True,
        "final_total": final_total
    }

def create_order_record(payment_details, final_total):
    # Implement order record creation logic here
    order = {
        "order_id": generate_unique_order_id(),
        "user_id": payment_details.get("user_id"),
        "items": payment_details.get("cart_with_tax"),
        "discount_applied": payment_details.get("total_discount"),
        "tax_amount": payment_details.get("tax_amount"),
        "final_total": final_total
    }
    return order

def generate_unique_order_id():
    import uuid
    return str(uuid.uuid4())

def multi_step_checkout(cart, discount_codes, user_permissions, tax_rate, payment_details):
    try:
        step1 = validate_cart_items(cart)
        step2 = apply_discount_codes(step1['validated_cart'], discount_codes, user_permissions)
        step3 = calculate_tax(step2['discounted_cart'], tax_rate)
        step4 = process_payment(step3['cart_with_tax'], step2['total_discount'], step3['tax_amount'], payment_details)
        return create_order_record(payment_details, step4['final_total'])
    except Exception as e:
        return {"error": str(e)}

